-- Training Material Lessons
INSERT INTO lessons (id, module_id, course_id, title, description, content_type, content_json, order_index, duration_minutes, is_published)
VALUES 
-- Overview Video
('lesson-t-overview', 'mod-training', 'smartwatch-course', 'Complete Project Overview', 'Watch this comprehensive overview of the entire smartwatch project and what you will build.', 'video',
'{"video_url":"https://www.youtube.com/watch?v=52L8VP05elU","video_type":"youtube","sections":[{"title":"What You Will Build","content":"A fully functioning smartwatch with real-time clock, touch interface, step counting, Wi-Fi connectivity, and custom screens. This is not a simulation - you will write production-quality firmware for real hardware."},{"title":"Learning Outcomes","content":"By the end of this program you will understand embedded C/C++ programming, hardware abstraction layers, RTOS task management, interrupt handling, I2C communication, and professional firmware architecture."},{"title":"Support","content":"If you need help, email support@shortcct.com with your specific questions and a zip file including your project directory. Virtual support is available for 3 months after your product delivery date."}],"resources":[{"title":"GitHub Repository","url":"https://github.com/short-circuit-projects/smartwatch","type":"github"},{"title":"T-Watch Schematic","url":"#","type":"document"},{"title":"T-Watch Pinout","url":"#","type":"document"}]}',
0, 20, 1),

-- Modular Architecture
('lesson-t-modular', 'mod-training', 'smartwatch-course', 'Modular Architecture', 'Learn how professional embedded firmware is structured for maintainability, debugging, and scalability.', 'text',
'{"sections":[{"title":"Why Modular Design?","content":"In professional embedded systems, firmware is rarely written as a single file. Instead, it is structured to be modular, maintainable, and scalable so that systems can grow, be debugged efficiently, and be worked on by multiple engineers."},{"title":"Directory Structure","content":"In PlatformIO it is recommended that you use the /include and /src directories for your header (.h) and source (.c/.cpp) files respectively.\n\n```\nproject/\n  include/\n    power.h\n    display.h\n    sensors.h\n  src/\n    power.cpp\n    display.cpp\n    sensors.cpp\n    main.cpp\n```"},{"title":"Benefits","content":"This organization makes each component independent and easier to debug, extend, or replace. Clean file boundaries allow different parts of the program to interact through well-defined interfaces."},{"title":"Key Principle","content":"Separate WHAT a module provides (declared in header files) from HOW it works (implemented in source files)."}],"key_points":["Modular design improves maintainability and scalability","Use /include for headers and /src for source files","Each module handles a specific responsibility","Clean interfaces allow independent testing"]}',
1, 15, 1),

-- File Structure
('lesson-t-files', 'mod-training', 'smartwatch-course', 'File Structure: Headers and Source Files', 'Understand the roles of header files (.h) and source files (.c/.cpp) in embedded projects.', 'text',
'{"sections":[{"title":"Header Files (.h)","content":"Header files define the interface and contain declarations - not executable code. They describe WHAT a module provides, not HOW it works.\n\n**Contents:**\n- Function prototypes\n- Constant definitions\n- Data type declarations (struct, enum, typedef)\n- Class declarations (C++)"},{"title":"Include Guards","content":"Always protect header files from multiple inclusion:\n\n```c\n#ifndef POWER_H\n#define POWER_H\n\n// Declarations here\nvoid initPower();\nint getBatteryPercent();\n\n#endif\n```"},{"title":"C Source Files (.c)","content":"Contain the actual implementations of functions declared in headers. This is where executable code lives.\n\n**Contents:**\n- Function definitions\n- Internal helper functions (often marked static)\n- Low-level driver logic"},{"title":"C++ Source Files (.cpp)","content":"Used when the project relies on C++ features like classes, objects, and encapsulation. Commonly used when interacting with Arduino or FreeRTOS libraries."}],"key_points":["Headers declare interfaces, source files implement them","Use include guards to prevent multiple inclusion","Mark internal helpers as static for encapsulation","C++ enables object-oriented design patterns"]}',
2, 15, 1),

-- Project Layers
('lesson-t-layers', 'mod-training', 'smartwatch-course', 'Project Layers', 'Learn the five-layer architecture model for professional embedded firmware.', 'text',
'{"sections":[{"title":"Layer 1: Hardware","content":"The physical electronics: microcontrollers, sensors, displays, and power components. No software exists at this level - all higher layers ultimately interact with the hardware."},{"title":"Layer 2: Hardware Abstraction Layer (HAL)","content":"The lowest level of software that interacts directly with hardware. Its purpose is to provide readable and reusable APIs that abstract away hardware registers and device-specific behavior.\n\n**Example:** A function like `i2c_write(addr, data)` hides the complexity of register manipulation."},{"title":"Layer 3: OS/Middleware/Service Layer","content":"Sits above hardware drivers and provides reusable software services:\n- Task scheduling (RTOS)\n- Timing services\n- Communication stacks\n- Sensor management\n\nIn systems using an RTOS, this layer includes OS services and middleware components."},{"title":"Layer 4: Application Logic Layer","content":"The \"brain\" of the device. Manages system states, decision-making, and interactions between components. Implements the product''s functionality without being tied to specific hardware details."},{"title":"Layer 5: Application Interface Layer","content":"The topmost layer responsible for presenting information to users or exposing APIs to other systems:\n- User interfaces\n- Display logic\n- Input handling\n- External communication"}],"key_points":["5-layer model: Hardware > HAL > Middleware > Logic > Interface","HAL isolates hardware-specific code from application logic","Layered design improves portability and maintainability","Not every project needs all 5 layers explicitly"]}',
3, 20, 1),

-- Pointers and References
('lesson-t-pointers', 'mod-training', 'smartwatch-course', 'Pointers and References', 'Master memory addresses, pointer arithmetic, and safe data passing techniques.', 'text',
'{"sections":[{"title":"What is a Pointer?","content":"A pointer is a variable that stores the memory address of another variable.\n\n```c\nint x = 42;\nint *ptr;        // Declare pointer\nptr = &x;        // Store address of x\n*ptr = 10;       // Modify x through pointer\n```"},{"title":"Why Pointers Matter in Embedded","content":"In embedded systems, pointers are essential for:\n- Passing large data structures without copying\n- Allowing functions to modify variables directly\n- Interfacing with hardware registers and memory-mapped I/O\n- Managing buffers, arrays, and shared state between tasks"},{"title":"Passing by Value vs Pointer","content":"```c\nvoid byValue(int x) {\n    x = 10;  // Only modifies local copy\n}\n\nvoid byPointer(int *x) {\n    *x = 10; // Modifies original variable\n}\n```"},{"title":"Pointers to Structures","content":"Use the arrow operator (->) for accessing members through pointers:\n\n```c\nstruct Sensor { int value; };\nstruct Sensor *s;\ns->value = 100;  // Same as (*s).value = 100\n```"},{"title":"The const Keyword","content":"- `const int *p` - pointer to constant data (cannot modify data)\n- `int *const p` - constant pointer (cannot change address)\n- `const int *const p` - both constant"}],"key_points":["Pointers store memory addresses","Use & to get address, * to dereference","Pass by pointer to modify original data","Use const to protect data and prevent bugs"],"resources":[{"title":"Pointers Tutorial Video","url":"https://www.youtube.com/watch?v=syy-3fVicUc","type":"youtube"}]}',
4, 25, 1),

-- Bit Manipulation
('lesson-t-bits', 'mod-training', 'smartwatch-course', 'Bit Manipulation', 'Learn bitwise operators essential for working with hardware registers and sensor data.', 'text',
'{"sections":[{"title":"Why Bit Manipulation?","content":"Embedded hardware frequently represents information using individual bits, bit fields, and packed binary values. Configuration registers, status flags, and sensor data are often encoded in ways that require firmware to extract or modify specific bits.\n\n**Example:** The PCF8563 RTC stores the hour value in just 6 bits, while bit 7 indicates clock integrity."},{"title":"Bitwise Operators","content":"| Operator | Purpose | Example |\n|----------|---------|--------|\n| & (AND) | Clear/select bits | `value & 0x7F` clears bit 7 |\n| \\| (OR) | Set bits | `value \\| 0x80` sets bit 7 |\n| ^ (XOR) | Toggle bits | `value ^ 0x01` flips bit 0 |\n| ~ (NOT) | Invert all | `~0x0F` gives `0xF0` |\n| << | Left shift | `1 << 3` gives `0x08` |\n| >> | Right shift | `0x80 >> 4` gives `0x08` |"},{"title":"Bit Masking","content":"A bit mask is a predefined pattern used to isolate or manipulate specific bits:\n\n```c\n// Extract lower 7 bits (clear bit 7)\nuint8_t seconds = raw_value & 0x7F;\n\n// Set bit 3\nreg |= (1 << 3);\n\n// Clear bit 2\nreg &= ~(1 << 2);\n\n// Toggle bit 1\nreg ^= (1 << 1);\n```"},{"title":"BCD Conversion","content":"Many RTCs use Binary Coded Decimal (BCD) format:\n\n```c\nuint8_t bcdToDec(uint8_t bcd) {\n    return (bcd >> 4) * 10 + (bcd & 0x0F);\n}\n\nuint8_t decToBcd(uint8_t dec) {\n    return ((dec / 10) << 4) | (dec % 10);\n}\n```"}],"key_points":["Hardware registers use individual bits for flags/values","AND (&) clears bits, OR (|) sets bits, XOR (^) toggles","Use masks to isolate specific bit fields","BCD format is common in RTC chips"],"resources":[{"title":"Binary and Bitwise Operators","url":"https://www.youtube.com/watch?v=WBim3afbYQw","type":"youtube"}]}',
5, 20, 1),

-- I2C Communication
('lesson-t-i2c', 'mod-training', 'smartwatch-course', 'I2C Communication', 'Understand the I2C protocol for communicating with sensors and peripherals.', 'text',
'{"sections":[{"title":"What is I2C?","content":"I2C (Inter-Integrated Circuit) is a widely used two-wire serial communication protocol for connecting microcontrollers to peripheral devices such as sensors, displays, real-time clocks, and power-management ICs.\n\n**Bus signals:**\n- SCL: Serial clock line (driven by master)\n- SDA: Bidirectional data line"},{"title":"Hardware Requirements","content":"I2C uses an open-drain configuration - devices can only pull lines LOW, never drive HIGH. External pull-up resistors (typically 4.7k ohms) are required.\n\n**Good news:** On the T-Watch platform, the required pull-up resistors are already present on the board."},{"title":"Addressing","content":"Each slave device has a unique 7-bit address (e.g., 0x51 for RTC, 0x38 for touch controller). Multiple devices share the same SDA and SCL lines."},{"title":"Transaction Sequence","content":"Every I2C transaction follows this sequence:\n1. START condition\n2. Slave address + R/W bit\n3. ACK from receiver\n4. Data bytes (with ACKs)\n5. STOP condition"},{"title":"ESP32 Implementation","content":"```cpp\n#include <Wire.h>\n\nvoid setup() {\n    Wire.begin(SDA_PIN, SCL_PIN);\n}\n\nvoid readRegister(uint8_t addr, uint8_t reg) {\n    Wire.beginTransmission(addr);\n    Wire.write(reg);\n    Wire.endTransmission();\n    Wire.requestFrom(addr, 1);\n    return Wire.read();\n}\n```"},{"title":"Error Handling","content":"Always check return values! On ESP32, functions typically return esp_err_t. Check for ESP_OK to ensure successful communication."}],"key_points":["I2C uses two wires: SDA (data) and SCL (clock)","Each device has a unique 7-bit address","Pull-up resistors are required (already on T-Watch)","Always check return values for errors"],"resources":[{"title":"I2C Protocol Overview","url":"https://www.youtube.com/watch?v=CAvawEcxoPU","type":"youtube"}]}',
6, 25, 1),

-- Object-Oriented Basics
('lesson-t-oop', 'mod-training', 'smartwatch-course', 'Object-Oriented Programming Basics', 'Learn C++ classes and objects for managing hardware complexity.', 'text',
'{"sections":[{"title":"Why OOP in Embedded?","content":"Object-oriented programming helps manage complexity by encapsulating hardware control logic within classes. This is common when building drivers for displays, sensors, or communication interfaces."},{"title":"Classes and Objects","content":"A **class** is a blueprint for data and functions. It defines what data an object holds and what operations it can perform.\n\nAn **object** is an instance of a class that exists in memory. Each object maintains its own internal state.\n\n```cpp\nclass Display {\nprivate:\n    int brightness;\n    bool isOn;\n    \npublic:\n    void init();\n    void setBrightness(int level);\n    void drawText(const char* text);\n};\n\n// Create objects\nDisplay mainDisplay;    // Instance 1\nDisplay secondDisplay;  // Instance 2\n```"},{"title":"Member Variables and Functions","content":"**Member variables** store the internal state of an object.\n\n**Member functions** define the behavior and operate on member variables.\n\nEach object gets its own copy of member variables, allowing multiple instances to operate independently."},{"title":"Access Specifiers","content":"**public:** Accessible from outside the class - the official interface\n**private:** Only accessible within the class - internal implementation\n\n```cpp\ntemp.getValue();    // OK - public method\ntemp.rawValue = 5;  // ERROR - private variable\n```"},{"title":"Constructors","content":"Special functions that initialize member variables when an object is created:\n\n```cpp\nclass Motor {\npublic:\n    Motor(int pin) {\n        controlPin = pin;\n        speed = 0;\n    }\nprivate:\n    int controlPin;\n    int speed;\n};\n```"}],"key_points":["Classes are blueprints, objects are instances","Member variables store state, member functions define behavior","Use public for interfaces, private for implementation","Constructors initialize objects when created"]}',
7, 20, 1),

-- RTOS
('lesson-t-rtos', 'mod-training', 'smartwatch-course', 'Real Time Operating System (RTOS)', 'Learn FreeRTOS fundamentals for concurrent task management.', 'text',
'{"sections":[{"title":"What is RTOS?","content":"A Real Time Operating System enables multiple pieces of code, known as tasks, to execute seemingly at the same time on a single processor. This is achieved through rapid context switching, where the scheduler determines which task runs at any given moment based on priority and timing requirements."},{"title":"Tasks","content":"A task represents an independent thread of execution with its own stack and context.\n\n```cpp\nvoid sensorTask(void *param) {\n    while(1) {\n        readSensors();\n        vTaskDelay(pdMS_TO_TICKS(100));\n    }\n}\n\n// Create task\nxTaskCreate(\n    sensorTask,    // Function\n    \"Sensors\",     // Name\n    2048,          // Stack size\n    NULL,          // Parameters\n    1,             // Priority\n    NULL           // Handle\n);\n```"},{"title":"Task Guidelines","content":"- Tasks must never return (use infinite loop)\n- Use vTaskDelay() instead of blocking delays\n- Allocate sufficient stack space\n- Too many tasks increases overhead"},{"title":"Semaphores and Mutexes","content":"**Binary Semaphore:** Acts as a signal or flag. Used to notify tasks when events occur.\n\n```cpp\nSemaphoreHandle_t dataReady = xSemaphoreCreateBinary();\n\n// In ISR\nxSemaphoreGiveFromISR(dataReady, NULL);\n\n// In task\nxSemaphoreTake(dataReady, portMAX_DELAY);\n```\n\n**Mutex:** Protects shared resources. Ensures only one task accesses a resource at a time.\n\n```cpp\nSemaphoreHandle_t i2cMutex = xSemaphoreCreateMutex();\n\nxSemaphoreTake(i2cMutex, portMAX_DELAY);\n// Access I2C bus safely\nxSemaphoreGive(i2cMutex);\n```"}],"key_points":["RTOS enables concurrent execution through task scheduling","Tasks must use vTaskDelay(), not blocking delays","Semaphores signal events between tasks/ISRs","Mutexes protect shared resources from race conditions"],"resources":[{"title":"FreeRTOS Tutorial","url":"https://www.youtube.com/watch?v=F321087yYy4&list=PLEBQazB0HUyQ4hAPU1cJED6t3DU0h34bz&index=1","type":"youtube"}]}',
8, 30, 1),

-- Static and Volatile
('lesson-t-static-volatile', 'mod-training', 'smartwatch-course', 'Static and Volatile Keywords', 'Understand these critical keywords for safe embedded development.', 'text',
'{"sections":[{"title":"The Static Keyword","content":"**Inside functions:** Variable retains its value between calls\n```c\nvoid counter() {\n    static int count = 0;  // Initialized once\n    count++;               // Persists across calls\n}\n```\n\n**For global variables/functions:** Limits visibility to the source file (file-scoping)\n```c\nstatic int internalState;  // Only visible in this file\nstatic void helperFunc();  // Private to this file\n```"},{"title":"The Volatile Keyword","content":"Tells the compiler that a variable''s value may change at any time, even if the current code doesn''t modify it.\n\n**Why it matters:** Without volatile, the compiler may optimize by caching values in registers, missing updates from ISRs or hardware.\n\n```c\nvolatile bool buttonPressed = false;\n\nvoid IRAM_ATTR buttonISR() {\n    buttonPressed = true;  // Modified by interrupt\n}\n\nvoid loop() {\n    if (buttonPressed) {  // Must read from memory\n        // Handle button\n        buttonPressed = false;\n    }\n}\n```"},{"title":"Using Both Together","content":"Common pattern for ISR-shared variables:\n\n```c\nstatic volatile bool dataReady = false;\n```\n\n**static:** Keeps variable private to this file\n**volatile:** Ensures ISR changes are visible"},{"title":"When to Use","content":"- **static:** Local variables that need persistence, file-private globals\n- **volatile:** Variables modified by ISRs, hardware registers, variables shared between tasks without mutex protection"}],"key_points":["static preserves value between calls or limits file scope","volatile forces memory access, prevents optimization issues","Use volatile for all ISR-shared variables","Combine both for file-private ISR-shared state"]}',
9, 15, 1),

-- Timing and Scheduling
('lesson-t-timing', 'mod-training', 'smartwatch-course', 'Timing and Scheduling', 'Master blocking vs non-blocking delays and hardware timers.', 'text',
'{"sections":[{"title":"Why Timing Matters","content":"In a smartwatch, nearly every subsystem depends on precise and predictable timing:\n- Screen refreshes\n- Accelerometer interrupts\n- Power management\n- Step counting\n- Touch input\n- Battery polling\n\nPoor timing decisions lead to missed events, sluggish UI, excessive power consumption, or system instability."},{"title":"Blocking Delays - AVOID","content":"Halts program execution entirely. The processor cannot do anything else.\n\n```cpp\ndelay(1000);  // BAD - freezes everything for 1 second\n```\n\n**Problems:**\n- Freezes UI and animations\n- Disrupts step counting\n- Wastes power (CPU active but idle)\n- Misses sensor events"},{"title":"Non-Blocking Delays - BASIC","content":"Check elapsed time without stopping execution:\n\n```cpp\nunsigned long lastUpdate = 0;\n\nvoid loop() {\n    if (millis() - lastUpdate > 1000) {\n        updateDisplay();\n        lastUpdate = millis();\n    }\n    // Other code continues running\n}\n```\n\nGood for early development and simple polling loops."},{"title":"RTOS Timing - RECOMMENDED","content":"Once using FreeRTOS, use vTaskDelay():\n\n```cpp\nvoid displayTask(void *param) {\n    while(1) {\n        updateDisplay();\n        vTaskDelay(pdMS_TO_TICKS(40));  // ~25 FPS\n    }\n}\n```\n\n**Benefits:**\n- Task suspends, scheduler runs other tasks\n- System remains responsive\n- Power efficient"},{"title":"Debouncing","content":"Physical buttons produce multiple electrical transitions per press. Debouncing filters these over time to detect single, intentional inputs.\n\n```cpp\nif (digitalRead(BUTTON) == LOW) {\n    delay(50);  // Simple debounce delay\n    if (digitalRead(BUTTON) == LOW) {\n        // Valid button press\n    }\n}\n```"}],"key_points":["Avoid blocking delays in production firmware","Use non-blocking checks (millis()) for simple polling","Use vTaskDelay() when running RTOS tasks","Debounce physical inputs to filter noise"]}',
10, 20, 1),

-- Interrupts and ISRs
('lesson-t-interrupts', 'mod-training', 'smartwatch-course', 'Interrupts and ISRs', 'Learn low-latency hardware event handling.', 'text',
'{"sections":[{"title":"What is an Interrupt?","content":"A hardware or software signal that temporarily pauses normal program execution so the processor can respond immediately to an important event.\n\n**Use cases:**\n- Button presses\n- Sensor data ready\n- Touch events\n- Power management alerts"},{"title":"How Interrupts Work","content":"1. Event occurs (button pressed)\n2. Processor pauses current execution\n3. Saves internal state (registers, program counter)\n4. Jumps to Interrupt Service Routine (ISR)\n5. ISR executes quickly\n6. Returns to original program flow"},{"title":"IRAM_ATTR Attribute","content":"On ESP32, application code runs from external flash memory. If an interrupt occurs while flash is busy, the system can crash.\n\n**Solution:** Use IRAM_ATTR to place ISR code in internal RAM:\n\n```cpp\nvoid IRAM_ATTR buttonISR() {\n    buttonPressed = true;  // Quick - just set flag\n}\n```"},{"title":"Trigger Types","content":"- **Falling edge:** HIGH to LOW transition\n- **Rising edge:** LOW to HIGH transition\n- **Change:** Any transition\n- **Level:** While signal is at a certain level\n\nThe T-Watch uses falling edge interrupts for touch and accelerometer."},{"title":"ISR Best Practices","content":"1. Keep ISRs extremely short\n2. Only set flags or signal semaphores\n3. Never use blocking calls or Serial.print()\n4. Clear interrupt status registers (e.g., axp.clearIRQ())\n5. Defer all heavy processing to tasks\n\n```cpp\nvolatile bool touchEvent = false;\n\nvoid IRAM_ATTR touchISR() {\n    touchEvent = true;  // Just set flag\n}\n\nvoid loop() {\n    if (touchEvent) {\n        touchEvent = false;\n        handleTouch();  // Heavy processing here\n    }\n}\n```"}],"key_points":["Interrupts enable near-instant response to events","Use IRAM_ATTR for all hardware ISRs on ESP32","Keep ISRs minimal - set flags, signal semaphores","Defer heavy processing to main code or tasks"]}',
11, 20, 1),

-- Finite State Machine
('lesson-t-fsm', 'mod-training', 'smartwatch-course', 'Finite State Machine (FSM)', 'Model complex system behavior with states and transitions.', 'text',
'{"sections":[{"title":"What is an FSM?","content":"A finite state machine is a structured model that organizes system behavior into a finite number of well-defined states, with clear rules governing transitions between those states.\n\n**Why use FSMs:**\n- Makes behavior predictable and modular\n- Easy to reason about and debug\n- Natural fit for UI navigation, power modes, protocols"},{"title":"Components","content":"**States:** Distinct modes of operation (Home screen, Settings, Sleep)\n\n**Transitions:** Rules for moving between states (button press, timeout)\n\n**Actions:** Behavior when entering, during, or exiting a state"},{"title":"Example: Screen Navigation","content":"```cpp\nenum ScreenState {\n    HOME_SCREEN,\n    STEPS_SCREEN,\n    WIFI_SCREEN,\n    STOPWATCH_SCREEN\n};\n\nScreenState currentScreen = HOME_SCREEN;\n\nvoid handleButton() {\n    switch (currentScreen) {\n        case HOME_SCREEN:\n            currentScreen = STEPS_SCREEN;\n            break;\n        case STEPS_SCREEN:\n            currentScreen = WIFI_SCREEN;\n            break;\n        // ...\n    }\n}\n\nvoid updateDisplay() {\n    switch (currentScreen) {\n        case HOME_SCREEN:\n            drawHomeScreen();\n            break;\n        case STEPS_SCREEN:\n            drawStepsScreen();\n            break;\n        // ...\n    }\n}\n```"},{"title":"Implementation Tips","content":"- Use enums for state values (readable, compiler-checked)\n- Keep state logic isolated in functions\n- Consider function pointers for complex systems\n- FSMs integrate well with RTOS task modes"}],"key_points":["FSMs organize behavior into discrete states","Use enums for type-safe state representation","Transitions are triggered by events or conditions","Ideal for UI navigation, power modes, protocols"]}',
12, 20, 1),

-- Networking
('lesson-t-networking', 'mod-training', 'smartwatch-course', 'Networking and Wi-Fi', 'Connect your smartwatch to Wi-Fi and synchronize time.', 'text',
'{"sections":[{"title":"ESP32 Wi-Fi Capabilities","content":"The ESP32 includes an integrated Wi-Fi radio and full TCP/IP networking stack. It can function like a small computer on a local network.\n\n**Important:** ESP32 supports only 2.4 GHz Wi-Fi networks. If your router uses 5 GHz only, use a mobile hotspot instead."},{"title":"Operating Modes","content":"**Station Mode:** Connect to an existing network (home router, hotspot)\n**Access Point Mode:** Create your own network that other devices connect to\n\nFor smartwatch applications, station mode is typically used."},{"title":"Connection Example","content":"```cpp\n#include <WiFi.h>\n\nconst char* ssid = \"YourNetworkName\";\nconst char* password = \"YourPassword\";\n\nvoid setup() {\n    WiFi.begin(ssid, password);\n    \n    while (WiFi.status() != WL_CONNECTED) {\n        delay(500);\n    }\n    // Connected!\n}\n```"},{"title":"NTP Time Synchronization","content":"Network Time Protocol allows synchronizing the RTC with internet time servers:\n\n```cpp\n#include <time.h>\n\nconst long gmtOffset = -18000;  // EST (UTC-5)\nconst int daylightOffset = 3600;\nconst char* ntpServer = \"pool.ntp.org\";\n\nvoid syncTime() {\n    configTime(gmtOffset, daylightOffset, ntpServer);\n    \n    struct tm timeinfo;\n    if (getLocalTime(&timeinfo)) {\n        // Update RTC with synced time\n    }\n}\n```"},{"title":"Power Considerations","content":"Wi-Fi connections consume significant power. Best practices:\n- Connect only when needed (startup, manual sync)\n- Disconnect after syncing\n- Use sleep modes when Wi-Fi is not required"}],"key_points":["ESP32 supports 2.4 GHz Wi-Fi only","Use station mode to connect to existing networks","NTP provides accurate internet time synchronization","Disable Wi-Fi when not needed to save battery"]}',
13, 20, 1);

-- ========================================
-- MODULE 1: SYSTEM BOOT
-- ========================================
INSERT INTO course_modules (id, course_id, title, description, order_index, is_published)
VALUES ('mod-1', 'smartwatch-course', 'Module 1: System Boot', 'Bring the smartwatch to life by initializing system power, displaying output on the screen, and handling hardware interrupts. By the end of this module, the watch should boot, display text, and respond to button presses.', 1, 1);

-- Module 1 Lessons
INSERT INTO lessons (id, module_id, course_id, title, description, content_type, content_json, order_index, duration_minutes, is_published)
VALUES 
('lesson-1-task1', 'mod-1', 'smartwatch-course', 'Task 1: Initialize System Power', 'Configure the AXP202 power management system for device boot.', 'text',
'{"sections":[{"title":"Objective","content":"Configure the power management system so the watch can boot and supply power to required peripherals."},{"title":"Background","content":"The AXP202 is a Power Management IC (PMIC) that controls power delivery to all components on the T-Watch. Before anything else can work, you must initialize this chip and enable the correct power rails."},{"title":"Implementation Steps","content":"1. **Use the AXP20X.h library** to control the AXP202 power management IC\n\n2. **Establish I2C communication** with the AXP202\n   - The AXP202 communicates over I2C\n   - Check the schematic for correct pins\n\n3. **Identify required power rails** using the schematic\n   - Which LDO powers the display backlight?\n   - Which LDO powers the ESP32?\n   - Which powers the sensors?\n\n4. **Enable the appropriate LDOs** to power the system and display\n\n5. **Review example code** provided by the AXP20X library"},{"title":"Code Structure","content":"```cpp\n// power.h\n#ifndef POWER_H\n#define POWER_H\n\nvoid initPower();\nint getBatteryPercent();\nbool isCharging();\n\n#endif\n\n// power.cpp\n#include <Wire.h>\n#include <axp20x.h>\n#include \"power.h\"\n\nAXP20X_Class axp;\n\nvoid initPower() {\n    Wire.begin(/* SDA, SCL pins */);\n    \n    if (!axp.begin(Wire)) {\n        // Handle error\n    }\n    \n    // Enable required LDOs\n    axp.setPowerOutPut(/* LDO channel */, AXP202_ON);\n}\n```"},{"title":"Deliverable Files","content":"- `power.h` - Function declarations\n- `power.cpp` - AXP202 initialization and control"}],"key_points":["AXP202 controls power to all components","Use I2C to communicate with the PMIC","Enable LDOs for display and peripherals","Check schematic for pin assignments"],"resources":[{"title":"AXP202 Datasheet","url":"#","type":"document"},{"title":"T-Watch Schematic","url":"#","type":"document"},{"title":"AXP20X Library","url":"https://github.com/lewisxhe/AXP202X_Library","type":"github"}]}',
0, 45, 1),

('lesson-1-task2', 'mod-1', 'smartwatch-course', 'Task 2: Display Text Using TFT_eSPI', 'Verify display functionality by rendering text after boot.', 'text',
'{"sections":[{"title":"Objective","content":"Verify that the display is functioning by printing text after system boot."},{"title":"Background","content":"The T-Watch uses an ST7789V display controller with a 240x240 pixel TFT LCD. The TFT_eSPI library provides optimized graphics functions for this display."},{"title":"Implementation Steps","content":"1. **Use the TFT_eSPI library** to interface with the ST7789V display\n\n2. **Initialize the display** before writing any graphics\n   - Set rotation appropriate for watch orientation\n   - Clear the screen with a background color\n\n3. **Print \"Hello World\"** after boot\n\n4. **Experiment** with text color, background color, and position"},{"title":"Code Structure","content":"```cpp\n// display.h\n#ifndef DISPLAY_H\n#define DISPLAY_H\n\nvoid initDisplay();\nvoid clearScreen();\nvoid drawText(const char* text, int x, int y);\nvoid setBacklight(int brightness);\n\n#endif\n\n// display.cpp\n#include <TFT_eSPI.h>\n#include \"display.h\"\n\nTFT_eSPI tft = TFT_eSPI();\n\nvoid initDisplay() {\n    tft.init();\n    tft.setRotation(2);  // Adjust as needed\n    tft.fillScreen(TFT_BLACK);\n    tft.setTextColor(TFT_WHITE, TFT_BLACK);\n    tft.setTextSize(2);\n}\n\nvoid drawText(const char* text, int x, int y) {\n    tft.drawString(text, x, y);\n}\n```"},{"title":"Testing","content":"After implementing, your watch should:\n1. Power on without errors\n2. Display \"Hello World\" centered on screen\n3. Show clear, readable text"},{"title":"Deliverable Files","content":"- `display.h` - Display function declarations\n- `display.cpp` - Display initialization and drawing"}],"key_points":["TFT_eSPI is optimized for ESP32 displays","Initialize display after power is configured","Set rotation to match watch orientation","Use setTextColor for foreground and background"],"resources":[{"title":"ST7789V Datasheet","url":"#","type":"document"},{"title":"TFT_eSPI Library","url":"https://github.com/Bodmer/TFT_eSPI","type":"github"}]}',
1, 45, 1),

('lesson-1-task3', 'mod-1', 'smartwatch-course', 'Task 3: Power Button Interrupt', 'Implement hardware interrupt to toggle display state.', 'text',
'{"sections":[{"title":"Objective","content":"Use a hardware interrupt to toggle the display on and off using the side button."},{"title":"Background","content":"The side button on the T-Watch is connected to an interrupt pin on the AXP202 power management IC. When pressed, it generates an interrupt that your firmware must handle."},{"title":"Implementation Steps","content":"1. **Identify the correct interrupt pin** using the schematic\n   - The side button connects through AXP202, not directly to ESP32\n   - Check for AXP interrupt (IRQ) pin connection\n\n2. **Create an ISR** with the IRAM_ATTR attribute\n   - Keep it minimal - just set a flag\n\n3. **In main loop**, check the flag and:\n   - Clear the interrupt with `axp.clearIRQ()`\n   - Toggle display state\n\n4. **Configure the AXP202** to generate interrupts on button press"},{"title":"Code Pattern","content":"```cpp\n// In power.cpp or main.cpp\nvolatile bool buttonPressed = false;\n\nvoid IRAM_ATTR buttonISR() {\n    buttonPressed = true;\n}\n\nvoid setup() {\n    initPower();\n    initDisplay();\n    \n    // Configure interrupt pin\n    pinMode(AXP_INT_PIN, INPUT_PULLUP);\n    attachInterrupt(AXP_INT_PIN, buttonISR, FALLING);\n    \n    // Enable AXP button interrupt\n    axp.enableIRQ(AXP202_PEK_SHORTPRESS_IRQ, true);\n}\n\nvoid loop() {\n    if (buttonPressed) {\n        buttonPressed = false;\n        axp.readIRQ();\n        \n        if (axp.isPEKShortPressIRQ()) {\n            toggleDisplay();\n        }\n        \n        axp.clearIRQ();\n    }\n}\n```"},{"title":"Important Notes","content":"- Always use `IRAM_ATTR` for hardware ISRs on ESP32\n- Never do heavy processing in the ISR\n- Always clear the interrupt status after handling\n- The AXP202 provides different interrupt types (short press, long press)"}],"key_points":["Button interrupt comes through AXP202","Use IRAM_ATTR for ESP32 ISR functions","Keep ISR minimal - just set a flag","Clear interrupt status after handling"],"callout":{"type":"warning","content":"Never call Serial.print(), delay(), or other blocking functions inside an ISR. This can crash your system."}}',
2, 60, 1),

('lesson-1-demo', 'mod-1', 'smartwatch-course', 'Module 1 Demo Submission', 'Submit a video demonstrating your Module 1 implementation.', 'submission',
'{"instructions":"Record a video demonstrating your completed Module 1 implementation. Your video should show:\n\n1. **System Boot** - Watch powering on successfully\n2. **Display Output** - \"Hello World\" or custom text displayed\n3. **Button Response** - Pressing the side button toggles the display\n\n**Video Requirements:**\n- 30 seconds to 2 minutes\n- Show the physical watch and screen clearly\n- Demonstrate each feature working\n- Brief verbal or text explanation is helpful but not required\n\n**Upload your project files as a ZIP including:**\n- power.h and power.cpp\n- display.h and display.cpp\n- main.cpp\n- platformio.ini","submission_type":"video","required_files":["power.h","power.cpp","display.h","display.cpp","main.cpp"],"rubric":[{"criteria":"Power initialization","points":25,"description":"AXP202 correctly initialized with required LDOs enabled"},{"criteria":"Display output","points":25,"description":"Text displays clearly on screen after boot"},{"criteria":"Button interrupt","points":30,"description":"Side button toggles display using interrupt-driven approach"},{"criteria":"Code quality","points":20,"description":"Clean file structure, proper abstractions, documented code"}]}',
3, 30, 1),

('lesson-1-quiz', 'mod-1', 'smartwatch-course', 'Module 1 Quiz', 'Test your understanding of system initialization concepts.', 'quiz',
