INSERT INTO quiz_questions (id, lesson_id, question_text, question_type, options_json, correct_answer, explanation, order_index, points)
VALUES 
('q1-1', 'lesson-1-quiz', 'What attribute must be used for ISR functions on ESP32?', 'multiple_choice', 
'["ICACHE_ATTR","IRAM_ATTR","ISR_ATTR","FLASH_ATTR"]', 'IRAM_ATTR', 
'IRAM_ATTR ensures the ISR code is placed in internal RAM so it is always available, even when flash memory is busy or being accessed.', 0, 10),

('q1-2', 'lesson-1-quiz', 'Why should ISR code be kept minimal?', 'multiple_choice',
'["To save program memory","To prevent blocking other interrupts and system operations","ISRs can only contain 10 lines of code","To make the code easier to read"]', 
'To prevent blocking other interrupts and system operations',
'Long ISRs can cause system instability by blocking other critical operations. Heavy processing should be deferred to main code or tasks.', 1, 10),

('q1-3', 'lesson-1-quiz', 'What is the purpose of the AXP202 chip in the T-Watch?', 'multiple_choice',
'["Display controller","Wi-Fi radio","Power management","Touch sensor"]',
'Power management',
'The AXP202 is a Power Management IC (PMIC) that controls power delivery to all components, manages battery charging, and monitors battery status.', 2, 10),

('q1-4', 'lesson-1-quiz', 'What should you always do after handling an AXP202 interrupt?', 'multiple_choice',
'["Restart the system","Clear the interrupt status","Disable the interrupt","Reset the display"]',
'Clear the interrupt status',
'Calling axp.clearIRQ() clears the interrupt status registers, allowing future interrupts to be detected. Without this, subsequent button presses may be missed.', 3, 10),

('q1-5', 'lesson-1-quiz', 'What communication protocol does the T-Watch use to communicate with the AXP202?', 'multiple_choice',
'["SPI","UART","I2C","USB"]',
'I2C',
'The AXP202 communicates over the I2C bus, which uses two wires (SDA and SCL) for data transfer.', 4, 10);

