INSERT INTO course_modules (id, course_id, title, description, order_index, is_published)
VALUES ('mod-2', 'smartwatch-course', 'Module 2: Timekeeping', 'Implement full system timekeeping. Store and retrieve time using the real-time clock, synchronize over Wi-Fi, and display date and time at controlled intervals.', 2, 1);

-- Module 2 Lessons
INSERT INTO lessons (id, module_id, course_id, title, description, content_type, content_json, order_index, duration_minutes, is_published)
VALUES 
('lesson-2-task1', 'mod-2', 'smartwatch-course', 'Task 1: RTC Storage and Retrieval', 'Use the PCF8563 to store and retrieve time across reboots.', 'text',
'{"sections":[{"title":"Objective","content":"Use the PCF8563 real-time clock to store and retrieve the current date and time. The RTC maintains time even when the main processor is off."},{"title":"Requirements","content":"- Time must be stored in 24-hour format (00:00 to 23:59)\n- Date must include month, day, and year\n- All firmware must be written in C using `driver/i2c.h` and `esp_err.h`\n- Time should persist across power cycles"},{"title":"PCF8563 Overview","content":"The PCF8563 is a real-time clock (RTC) chip that:\n- Communicates over I2C at address 0x51\n- Stores time in BCD (Binary Coded Decimal) format\n- Has backup battery to maintain time when power is off\n- Updates its registers every second"},{"title":"Implementation Steps","content":"1. **Use the `tm` structure** from the standard time library to represent date and time values\n\n2. **Write low-level byte read/write functions** for the RTC\n   - These handle raw I2C communication\n   \n3. **Wrap with higher-level functions** for external use\n   - `getTime()` and `setTime()` functions\n   \n4. **Use bcdToDec and decToBcd helpers** when reading/writing RTC registers\n\n5. **Study the PCF8563 datasheet** for register layout and bit masking"},{"title":"Register Layout","content":"| Register | Bits 7-4 | Bits 3-0 |\n|----------|----------|----------|\n| Seconds  | VL flag / tens | units |\n| Minutes  | unused / tens | units |\n| Hours    | unused / tens | units |\n| Days     | unused / tens | units |\n| Months   | Century / tens | units |\n| Years    | tens | units |\n\n**Note:** Bit 7 of seconds register is the VL (Voltage Low) flag indicating clock integrity."},{"title":"Code Structure","content":"```c\n// mytime.h\n#ifndef MYTIME_H\n#define MYTIME_H\n\n#include <time.h>\n\nesp_err_t rtc_init();\nesp_err_t rtc_get_time(struct tm *time);\nesp_err_t rtc_set_time(const struct tm *time);\n\n#endif\n\n// mytime.c\nstatic uint8_t bcdToDec(uint8_t bcd) {\n    return (bcd >> 4) * 10 + (bcd & 0x0F);\n}\n\nstatic uint8_t decToBcd(uint8_t dec) {\n    return ((dec / 10) << 4) | (dec % 10);\n}\n```"},{"title":"Deliverable Files","content":"- `mytime.h` - Time function declarations\n- `mytime.c` - RTC communication and time conversion logic"}],"key_points":["PCF8563 uses I2C address 0x51","Time values stored in BCD format","Mask bit 7 of seconds (VL flag)","Use bcdToDec/decToBcd for conversion"],"resources":[{"title":"PCF8563 Datasheet","url":"#","type":"document"}]}',
0, 60, 1),

('lesson-2-task2', 'mod-2', 'smartwatch-course', 'Task 2: Wi-Fi Time Synchronization', 'Sync time from the internet using NTP.', 'text',
'{"sections":[{"title":"Objective","content":"Connect to a Wi-Fi network during boot and retrieve the current time from the internet using the Network Time Protocol (NTP)."},{"title":"Requirements","content":"- Use the WiFi.h library to connect to a known 2.4 GHz network\n- Synchronize time using NTP after successful connection\n- If Wi-Fi is unavailable, the system should continue using the RTC\n- Update the RTC with the synchronized time"},{"title":"Implementation Steps","content":"1. **Initialize Wi-Fi** and attempt connection during startup\n   ```cpp\n   WiFi.begin(ssid, password);\n   ```\n\n2. **Wait for connection** with timeout\n   ```cpp\n   int timeout = 20; // 10 seconds\n   while (WiFi.status() != WL_CONNECTED && timeout > 0) {\n       delay(500);\n       timeout--;\n   }\n   ```\n\n3. **After connecting**, sync time with NTP\n   ```cpp\n   configTime(gmtOffset, daylightOffset, ntpServer);\n   ```\n\n4. **Get synchronized time**\n   ```cpp\n   struct tm timeinfo;\n   if (getLocalTime(&timeinfo)) {\n       rtc_set_time(&timeinfo);  // Update RTC\n   }\n   ```\n\n5. **Disconnect Wi-Fi** after sync to save power"},{"title":"Code Structure","content":"```cpp\n// mywifi.h\n#ifndef MYWIFI_H\n#define MYWIFI_H\n\nbool wifi_connect();\nvoid wifi_disconnect();\nbool wifi_sync_time();\nbool wifi_is_connected();\n\n#endif\n\n// mywifi.cpp\n#include <WiFi.h>\n#include \"mywifi.h\"\n\nconst char* ssid = \"YourSSID\";\nconst char* password = \"YourPassword\";\nconst char* ntpServer = \"pool.ntp.org\";\nconst long gmtOffset = -18000;  // UTC-5 (EST)\nconst int daylightOffset = 3600;\n\nbool wifi_connect() {\n    WiFi.begin(ssid, password);\n    int timeout = 20;\n    while (WiFi.status() != WL_CONNECTED && timeout > 0) {\n        delay(500);\n        timeout--;\n    }\n    return WiFi.status() == WL_CONNECTED;\n}\n```"},{"title":"Important Notes","content":"- **ESP32 only supports 2.4 GHz** Wi-Fi networks\n- If no 2.4 GHz network is available, use a mobile hotspot\n- Consider making credentials configurable rather than hardcoded\n- Wi-Fi consumes significant power - disconnect when not needed"},{"title":"Deliverable Files","content":"- `mywifi.h` - Wi-Fi function declarations\n- `mywifi.cpp` - Wi-Fi initialization and time synchronization"}],"key_points":["ESP32 supports 2.4 GHz Wi-Fi only","Use configTime() for NTP setup","Update RTC with synced time","Disconnect Wi-Fi after sync to save power"],"callout":{"type":"info","content":"If you don''t have access to a 2.4 GHz network, you can create a mobile hotspot from your phone."}}',
1, 45, 1),

('lesson-2-task3', 'mod-2', 'smartwatch-course', 'Task 3: Time Display Formatting', 'Display time and date with proper format and efficient updates.', 'text',
'{"sections":[{"title":"Objective","content":"Display the current time and date on the screen in a readable format. The display should update efficiently without unnecessary refreshes."},{"title":"Format Requirements","content":"- **Time:** HH:MM in 24-hour (military) format\n- **Date:** MM DD YYYY format\n- **Update rate:** Screen refreshes only once every 40 seconds to save power"},{"title":"Implementation Steps","content":"1. **Use snprintf** to format time and date strings\n   ```cpp\n   char timeStr[6];\n   snprintf(timeStr, sizeof(timeStr), \"%02d:%02d\", hour, minute);\n   \n   char dateStr[12];\n   snprintf(dateStr, sizeof(dateStr), \"%02d %02d %04d\", month, day, year);\n   ```\n\n2. **Implement non-blocking update logic**\n   ```cpp\n   static unsigned long lastUpdate = 0;\n   if (millis() - lastUpdate > 40000) {  // 40 seconds\n       updateTimeDisplay();\n       lastUpdate = millis();\n   }\n   ```\n\n3. **Integrate with display driver** cleanly\n   - Create dedicated functions for time display\n   - Position time and date appropriately on screen"},{"title":"Code Example","content":"```cpp\n// In display.cpp\nvoid drawTime(int hour, int minute) {\n    char timeStr[6];\n    snprintf(timeStr, sizeof(timeStr), \"%02d:%02d\", hour, minute);\n    \n    // Large font for time\n    tft.setTextSize(4);\n    tft.drawString(timeStr, 50, 80);\n}\n\nvoid drawDate(int month, int day, int year) {\n    char dateStr[12];\n    snprintf(dateStr, sizeof(dateStr), \"%02d %02d %04d\", month, day, year);\n    \n    // Smaller font for date\n    tft.setTextSize(2);\n    tft.drawString(dateStr, 60, 150);\n}\n```"},{"title":"Efficiency Considerations","content":"- Only redraw when the display actually changes\n- Consider redrawing only the changed digits\n- Use non-blocking delays to keep system responsive\n- Don''t block other system tasks while updating display"}],"key_points":["Use snprintf for safe string formatting","Update only every 40 seconds to save power","Use non-blocking approach for updates","Format: HH:MM for time, MM DD YYYY for date"]}',
2, 30, 1),

('lesson-2-demo', 'mod-2', 'smartwatch-course', 'Module 2 Demo Submission', 'Submit a video demonstrating your Module 2 implementation.', 'submission',
'{"instructions":"Record a video demonstrating your completed Module 2 implementation. Your video should show:\n\n1. **Time Display** - Current time shown in HH:MM format\n2. **Date Display** - Current date shown in MM DD YYYY format\n3. **Wi-Fi Sync** - If possible, show the watch syncing time (or explain your sync approach)\n4. **Time Persistence** - Show that time is retained (power cycle if possible)\n\n**Video Requirements:**\n- 30 seconds to 2 minutes\n- Show the time display clearly\n- Explain your time sync approach\n\n**Upload your project files as a ZIP including:**\n- mytime.h and mytime.c\n- mywifi.h and mywifi.cpp\n- display.h and display.cpp\n- main.cpp","submission_type":"video","required_files":["mytime.h","mytime.c","mywifi.h","mywifi.cpp"],"rubric":[{"criteria":"RTC implementation","points":30,"description":"PCF8563 correctly reads and writes time in BCD format"},{"criteria":"Wi-Fi sync","points":25,"description":"NTP synchronization implemented with proper timeout handling"},{"criteria":"Display formatting","points":25,"description":"Time and date displayed in correct formats with efficient updates"},{"criteria":"Code quality","points":20,"description":"Clean abstractions, proper error handling, documented code"}]}',
3, 30, 1),

('lesson-2-quiz', 'mod-2', 'smartwatch-course', 'Module 2 Quiz', 'Test your understanding of timekeeping concepts.', 'quiz',
'{"passing_score":70,"time_limit":15,"attempts_allowed":3,"instructions":"This quiz tests your understanding of the concepts covered in Module 2. You need 70% to pass."}',
