-- Module 2 Quiz Questions
INSERT INTO quiz_questions (id, lesson_id, question_text, question_type, options_json, correct_answer, explanation, order_index, points)
VALUES 
('q2-1', 'lesson-2-quiz', 'What format does the PCF8563 RTC use to store time values?', 'multiple_choice',
'["Binary","Decimal","BCD (Binary Coded Decimal)","Hexadecimal"]',
'BCD (Binary Coded Decimal)',
'The PCF8563 stores time values in BCD format, where each decimal digit (0-9) is represented by a 4-bit binary value.', 0, 10),

('q2-2', 'lesson-2-quiz', 'What is the I2C address of the PCF8563 RTC?', 'multiple_choice',
'["0x38","0x51","0x19","0x76"]',
'0x51',
'The PCF8563 has a fixed I2C address of 0x51 (hexadecimal).', 1, 10),

('q2-3', 'lesson-2-quiz', 'Why should you disconnect Wi-Fi after time synchronization?', 'multiple_choice',
'["Wi-Fi only works for 30 seconds","To save battery power","The RTC requires the Wi-Fi to be off","NTP servers require disconnection"]',
'To save battery power',
'Wi-Fi consumes significant power. Disconnecting after sync conserves battery life, which is critical for wearable devices.', 2, 10),

('q2-4', 'lesson-2-quiz', 'What Wi-Fi frequency does the ESP32 support?', 'multiple_choice',
'["5 GHz only","2.4 GHz only","Both 2.4 GHz and 5 GHz","6 GHz"]',
'2.4 GHz only',
'The ESP32 only supports 2.4 GHz Wi-Fi networks. 5 GHz networks are not compatible.', 3, 10),

('q2-5', 'lesson-2-quiz', 'What is the purpose of bit 7 (VL flag) in the PCF8563 seconds register?', 'multiple_choice',
'["Indicates AM/PM","Indicates battery low / clock integrity","Enables the alarm","Starts the stopwatch"]',
'Indicates battery low / clock integrity',
'The VL (Voltage Low) flag in bit 7 of the seconds register indicates whether the clock integrity is guaranteed. If set, the time may be invalid due to low voltage.', 4, 10);

