-- Module 3 Lessons
INSERT INTO lessons (id, module_id, course_id, title, description, content_type, content_json, order_index, duration_minutes, is_published)
VALUES 
('lesson-3-task1', 'mod-3', 'smartwatch-course', 'Task 1: Touch Coordinate Extraction', 'Implement a touch driver for the FT6236U controller.', 'text',
'{"sections":[{"title":"Objective","content":"Create a program that reads and displays the x and y coordinates of touch events on the smartwatch display."},{"title":"Technical Details","content":"- **FT6236U uses I2C address 0x38** (not explicitly listed in datasheet)\n- Use interrupt-driven approach for touch detection\n- Keep ISRs minimal, defer coordinate processing to main code\n- Parse x and y coordinates from device registers correctly"},{"title":"Implementation Steps","content":"1. **Set up I2C communication** with the FT6236U at address 0x38\n\n2. **Configure interrupt pin** for falling edge detection\n   - Touch controller generates interrupt when screen is touched\n\n3. **In ISR**, only set a touch flag\n   ```cpp\n   volatile bool touchEvent = false;\n   \n   void IRAM_ATTR touchISR() {\n       touchEvent = true;\n   }\n   ```\n\n4. **In main loop**, read coordinates when flag is set\n   - Read from FT6236U registers\n   - Extract x and y values (may need bit manipulation)\n\n5. **Display coordinates** on screen for testing"},{"title":"FT6236U Register Map","content":"The touch coordinates are stored in specific registers:\n\n| Register | Content |\n|----------|--------|\n| 0x02 | Number of touch points |\n| 0x03 | X position high byte (upper 4 bits) |\n| 0x04 | X position low byte |\n| 0x05 | Y position high byte (upper 4 bits) |\n| 0x06 | Y position low byte |\n\n```cpp\nuint16_t x = ((data[0] & 0x0F) << 8) | data[1];\nuint16_t y = ((data[2] & 0x0F) << 8) | data[3];\n```"},{"title":"Code Structure","content":"```c\n// touch.h\n#ifndef TOUCH_H\n#define TOUCH_H\n\nesp_err_t touch_init();\nbool touch_available();\nesp_err_t touch_read(uint16_t *x, uint16_t *y);\n\n#endif\n```"},{"title":"Deliverable Files","content":"- `touch.h` - Touch function declarations\n- `touch.c` - FT6236U communication and coordinate extraction"}],"key_points":["FT6236U uses I2C address 0x38","Use interrupt-driven approach, not polling","Extract coordinates from registers with bit manipulation","Display coordinates for testing"],"resources":[{"title":"FT6236U Datasheet","url":"#","type":"document"}]}',
0, 60, 1),

('lesson-3-demo1', 'mod-3', 'smartwatch-course', 'Task 1 Demo: Touch Coordinates', 'Submit a video showing touch coordinate display.', 'submission',
'{"instructions":"Record a short video demonstrating your touch coordinate implementation:\n\n1. Show the watch displaying touch coordinates as you touch different areas\n2. Demonstrate that coordinates update in real-time\n3. Show responses to touches in corners and center\n\n**Upload your touch.h and touch.c files with the video.**","submission_type":"video","required_files":["touch.h","touch.c"],"rubric":[{"criteria":"Interrupt handling","points":30,"description":"Touch events detected via interrupt, not polling"},{"criteria":"Coordinate accuracy","points":40,"description":"X and Y coordinates correctly extracted and displayed"},{"criteria":"Code quality","points":30,"description":"Clean driver implementation with proper I2C communication"}]}',
1, 15, 1),

('lesson-3-task2', 'mod-3', 'smartwatch-course', 'Task 2: Step Count Screen', 'Display step count from the BMA423 accelerometer.', 'text',
'{"sections":[{"title":"Objective","content":"Create a screen that displays the total step count stored in the BMA423 accelerometer."},{"title":"BMA423 Overview","content":"The BMA423 is a 3-axis accelerometer with built-in step counter:\n- Communicates over I2C\n- Has internal step counting algorithm\n- Stores cumulative step count in registers\n- Generates interrupts on step detection"},{"title":"Implementation Steps","content":"1. **Initialize the BMA423** accelerometer\n   - Use the provided BMA423 library/abstraction\n   - Configure for step counting mode\n\n2. **Retrieve the stored step count**\n   - The BMA423 maintains a cumulative count\n   - Read the step count register\n\n3. **Display in a readable format**\n   - Create a dedicated \"Steps\" screen\n   - Show the step count prominently\n   - Consider adding a step icon\n\n4. **Update periodically**\n   - Refresh the display at reasonable intervals\n   - Don''t read too frequently (wastes power)"},{"title":"Code Structure","content":"```cpp\n// accel.h\n#ifndef ACCEL_H\n#define ACCEL_H\n\nclass Accel {\npublic:\n    bool init();\n    uint32_t getStepCount();\n    void resetStepCount();\nprivate:\n    // Internal state\n};\n\n#endif\n\n// accel.cpp\n#include \"accel.h\"\n#include <bma423.h>  // BMA423 library\n\nbool Accel::init() {\n    // Initialize BMA423\n    // Enable step counting feature\n    return true;\n}\n\nuint32_t Accel::getStepCount() {\n    // Read step count from BMA423\n    return stepCount;\n}\n```"},{"title":"Important Notes","content":"- Use the provided accelerometer abstraction rather than accessing registers directly\n- The step counter is cumulative - it doesn''t reset automatically\n- Consider whether you want to persist step count across reboots"},{"title":"Deliverable Files","content":"- `accel.h` - Accelerometer class declaration\n- `accel.cpp` - BMA423 initialization and step count retrieval"}],"key_points":["Use provided BMA423 library abstraction","Step count is maintained internally by BMA423","Create a dedicated screen for step display","Update at reasonable intervals to save power"],"resources":[{"title":"BMA423 Datasheet","url":"#","type":"document"},{"title":"BMA423 Library","url":"#","type":"github"}]}',
2, 45, 1),

('lesson-3-demo2', 'mod-3', 'smartwatch-course', 'Task 2 Demo: Step Count Screen', 'Submit a video showing the step count display.', 'submission',
'{"instructions":"Record a short video demonstrating your step count screen:\n\n1. Show the step count displayed on screen\n2. If possible, demonstrate the count incrementing (shake the watch)\n3. Explain your implementation approach\n\n**Upload your accel.h and accel.cpp files with the video.**","submission_type":"video","required_files":["accel.h","accel.cpp"],"rubric":[{"criteria":"BMA423 initialization","points":30,"description":"Accelerometer correctly initialized with step counting enabled"},{"criteria":"Step count display","points":40,"description":"Step count retrieved and displayed in readable format"},{"criteria":"Code quality","points":30,"description":"Clean class-based implementation with proper abstractions"}]}',
3, 15, 1),

('lesson-3-task3', 'mod-3', 'smartwatch-course', 'Task 3: Wi-Fi Status Screen', 'Create a status display with manual reconnection button.', 'text',
'{"sections":[{"title":"Objective","content":"Create a screen that displays the current Wi-Fi connection status with the ability to manually reconnect."},{"title":"Required States","content":"Your Wi-Fi status screen must support three states:\n\n1. **Wi-Fi Connected**\n   - Display a connected icon\n   - Show the network SSID\n\n2. **Wi-Fi Connecting**\n   - Show a connecting indicator/animation\n   - Indicate connection attempt in progress\n\n3. **Wi-Fi Not Connected**\n   - Display a disconnected icon\n   - Show clear \"Not Connected\" status\n   - Display reconnect button"},{"title":"Implementation Steps","content":"1. **Track Wi-Fi state internally**\n   - Use an enum for state management\n   ```cpp\n   enum WiFiState { DISCONNECTED, CONNECTING, CONNECTED };\n   WiFiState currentState = DISCONNECTED;\n   ```\n\n2. **Use helper functions** for drawing\n   - `drawWiFiSymbol()` - Wi-Fi icon\n   - `drawRefreshSymbol()` - Reconnect button\n\n3. **Update screen responsively**\n   - State changes should reflect immediately\n   - Don''t update excessively when idle\n\n4. **Implement manual reconnection**\n   - Detect touch on reconnect button\n   - Attempt Wi-Fi connection\n   - Update state based on result"},{"title":"Code Structure","content":"```cpp\n// mywifi.h (extended)\nclass MyWiFi {\npublic:\n    enum State { DISCONNECTED, CONNECTING, CONNECTED };\n    \n    bool connect();\n    void disconnect();\n    State getState();\n    const char* getSSID();\n    void drawStatusScreen();\nprivate:\n    State state;\n};\n```"},{"title":"UI Considerations","content":"- Make the reconnect button easy to touch (large touch target)\n- Consider using a touch callback for button detection\n- Show clear visual feedback during connection attempts\n- Display meaningful information (SSID when connected)"},{"title":"Deliverable Files","content":"Update `mywifi.h` and `mywifi.cpp` with the MyWiFi class implementation"}],"key_points":["Support three states: Connected, Connecting, Disconnected","Show SSID when connected","Implement manual reconnect button","Track state internally with enum"]}',
4, 45, 1),

('lesson-3-demo3', 'mod-3', 'smartwatch-course', 'Task 3 Demo: Wi-Fi Status Screen', 'Submit a video showing the Wi-Fi status screen.', 'submission',
'{"instructions":"Record a video demonstrating your Wi-Fi status screen:\n\n1. Show the connected state with SSID displayed\n2. Demonstrate the reconnect button functionality\n3. Show the connecting state (if possible)\n4. Show the disconnected state\n\n**Upload your updated mywifi.h and mywifi.cpp files with the video.**","submission_type":"video","required_files":["mywifi.h","mywifi.cpp"],"rubric":[{"criteria":"State management","points":25,"description":"Three Wi-Fi states correctly tracked and displayed"},{"criteria":"Connected display","points":25,"description":"SSID shown when connected with appropriate icon"},{"criteria":"Reconnect button","points":30,"description":"Manual reconnect button works correctly"},{"criteria":"Code quality","points":20,"description":"Clean class-based implementation with proper state handling"}]}',
5, 15, 1),

