-- Module 4 Lessons
INSERT INTO lessons (id, module_id, course_id, title, description, content_type, content_json, order_index, duration_minutes, is_published)
VALUES 
('lesson-4-task1', 'mod-4', 'smartwatch-course', 'Task 1: Stopwatch Screen', 'Create a persistent stopwatch with start/stop/reset functionality.', 'text',
'{"sections":[{"title":"Objective","content":"Create a stopwatch screen that supports start, stop, and reset functionality. The stopwatch must continue running even when navigating away from the stopwatch screen."},{"title":"Requirements","content":"- Display format: **HH:MM:SS**\n- Support **Start**, **Stop**, and **Reset** functions\n- **Continue running in background** when on other screens\n- Use **semaphores** for display coordination"},{"title":"Key Design Decision","content":"**Separate timing logic from display rendering.**\n\nThe stopwatch state must persist independently of which screen is active. This means:\n- A background task or variable tracks elapsed time\n- The display only renders the current state\n- Navigation doesn''t affect the running stopwatch"},{"title":"Implementation Approach","content":"1. **Use a separate timing variable**\n   ```cpp\n   static unsigned long stopwatchStartTime = 0;\n   static unsigned long stopwatchElapsed = 0;\n   static bool stopwatchRunning = false;\n   ```\n\n2. **Start function**\n   ```cpp\n   void startStopwatch() {\n       stopwatchStartTime = millis();\n       stopwatchRunning = true;\n   }\n   ```\n\n3. **Get current time**\n   ```cpp\n   unsigned long getStopwatchTime() {\n       if (stopwatchRunning) {\n           return stopwatchElapsed + (millis() - stopwatchStartTime);\n       }\n       return stopwatchElapsed;\n   }\n   ```\n\n4. **Display function** (called only when stopwatch screen is active)\n   ```cpp\n   void drawStopwatchScreen() {\n       unsigned long ms = getStopwatchTime();\n       int hours = ms / 3600000;\n       int mins = (ms / 60000) % 60;\n       int secs = (ms / 1000) % 60;\n       // Draw formatted time\n   }\n   ```"},{"title":"Touch Buttons","content":"Create three touch button areas:\n- **START/STOP** button (toggle)\n- **RESET** button (only when stopped)\n\nUse touch coordinates to detect button presses."},{"title":"RTOS Consideration","content":"If using RTOS, you might run stopwatch timing in a dedicated task:\n```cpp\nvoid stopwatchTask(void *param) {\n    while(1) {\n        if (stopwatchRunning) {\n            // Update display if on stopwatch screen\n        }\n        vTaskDelay(pdMS_TO_TICKS(100));\n    }\n}\n```"}],"key_points":["Stopwatch must persist across screen changes","Separate timing logic from display rendering","Use millis() for timing, not delays","Format output as HH:MM:SS"]}',
0, 60, 1),

('lesson-4-task2', 'mod-4', 'smartwatch-course', 'Task 2: Screen Navigation', 'Implement touch-based navigation between all screens.', 'text',
'{"sections":[{"title":"Objective","content":"Design and implement touch buttons that allow navigation between all previously created screens."},{"title":"Screens to Support","content":"Your navigation system must support switching between:\n1. **Home Screen** - Time and date display\n2. **Steps Screen** - Step count from accelerometer\n3. **Wi-Fi Screen** - Connection status and reconnect\n4. **Stopwatch Screen** - Timer with controls"},{"title":"Implementation Guidelines","content":"1. **Centralize screen state management**\n   ```cpp\n   enum Screen { HOME, STEPS, WIFI, STOPWATCH };\n   Screen currentScreen = HOME;\n   ```\n\n2. **Use touch events for transitions**\n   - Don''t poll continuously\n   - React to touch interrupt events\n\n3. **Ensure only one screen is active**\n   ```cpp\n   void setScreen(Screen newScreen) {\n       currentScreen = newScreen;\n       clearDisplay();\n       drawCurrentScreen();\n   }\n   ```\n\n4. **Make interactions responsive and consistent**"},{"title":"Navigation Options","content":"Several approaches for navigation buttons:\n\n**Option 1: On-screen buttons**\n- Draw navigation icons at bottom of screen\n- Detect touches in button areas\n\n**Option 2: Swipe gestures**\n- Detect swipe direction from touch coordinates\n- Left/right swipe changes screens\n\n**Option 3: Physical button**\n- Use side button to cycle through screens"},{"title":"FSM Pattern","content":"```cpp\nvoid updateDisplay() {\n    switch (currentScreen) {\n        case HOME:\n            drawHomeScreen();\n            break;\n        case STEPS:\n            drawStepsScreen();\n            break;\n        case WIFI:\n            drawWiFiScreen();\n            break;\n        case STOPWATCH:\n            drawStopwatchScreen();\n            break;\n    }\n}\n\nvoid handleNavigation(int x, int y) {\n    // Check if touch is in navigation area\n    if (y > 200) {  // Bottom navigation bar\n        if (x < 60) setScreen(HOME);\n        else if (x < 120) setScreen(STEPS);\n        else if (x < 180) setScreen(WIFI);\n        else setScreen(STOPWATCH);\n    }\n}\n```"}],"key_points":["Centralize screen state in single variable","Use touch events, not polling","Only one screen active at a time","Consider FSM pattern for clean organization"]}',
1, 45, 1),

('lesson-4-task3', 'mod-4', 'smartwatch-course', 'Task 3: Battery Display', 'Show live battery percentage on the home screen.', 'text',
'{"sections":[{"title":"Objective","content":"Display real-time battery percentage on the home screen using data from the AXP202 power management IC."},{"title":"Implementation Steps","content":"1. **Read battery data** using the AXP20X library\n   ```cpp\n   int batteryPercent = axp.getBattPercentage();\n   bool isCharging = axp.isCharging();\n   float voltage = axp.getBattVoltage();\n   ```\n\n2. **Use drawBatterySymbol function**\n   - Create or use provided helper function\n   - Pass battery percentage value\n   - Position appropriately on home screen\n\n3. **Update dynamically**\n   - Refresh at reasonable intervals (not every frame)\n   - Don''t interfere with other display operations"},{"title":"Battery Icon Design","content":"```cpp\nvoid drawBatterySymbol(int percent) {\n    // Draw battery outline\n    tft.drawRect(x, y, 30, 15, TFT_WHITE);\n    tft.fillRect(x+30, y+4, 3, 7, TFT_WHITE);  // Tip\n    \n    // Fill based on percentage\n    int fillWidth = (percent * 28) / 100;\n    uint16_t color = percent > 20 ? TFT_GREEN : TFT_RED;\n    tft.fillRect(x+1, y+1, fillWidth, 13, color);\n    \n    // Show percentage text\n    char pctStr[5];\n    snprintf(pctStr, sizeof(pctStr), \"%d%%\", percent);\n    tft.drawString(pctStr, x+35, y);\n}\n```"},{"title":"Charging Indicator","content":"Consider adding a charging indicator:\n- Lightning bolt icon when charging\n- Different color when charging vs discharging\n- Animation for charging state"},{"title":"Update Frequency","content":"Battery percentage changes slowly. Update every 30-60 seconds:\n```cpp\nstatic unsigned long lastBatteryUpdate = 0;\nif (millis() - lastBatteryUpdate > 30000) {\n    updateBatteryDisplay();\n    lastBatteryUpdate = millis();\n}\n```"}],"key_points":["Use axp.getBattPercentage() for reading","Position battery icon on home screen","Update every 30-60 seconds, not continuously","Consider charging indicator"]}',
2, 30, 1),

('lesson-4-task4', 'mod-4', 'smartwatch-course', 'Task 4: RTOS Architecture', 'Structure firmware using FreeRTOS for concurrent operation.', 'text',
'{"sections":[{"title":"Objective","content":"Structure the firmware using a Real Time Operating System to handle multiple subsystems concurrently and reliably."},{"title":"Recommended Task Structure","content":"Create separate tasks for different responsibilities:\n\n| Task | Priority | Purpose |\n|------|----------|--------|\n| Input Task | High (3) | Handle touch and button events |\n| Display Task | Medium (2) | Update screen content |\n| Timekeeping Task | Medium (2) | Update RTC, manage time |\n| Sensor Task | Low (1) | Poll accelerometer, update steps |\n| Network Task | Low (1) | Handle Wi-Fi when needed |"},{"title":"Task Creation","content":"```cpp\nvoid setup() {\n    // Initialize hardware first\n    initPower();\n    initDisplay();\n    initTouch();\n    initSensors();\n    \n    // Create tasks\n    xTaskCreate(inputTask, \"Input\", 2048, NULL, 3, NULL);\n    xTaskCreate(displayTask, \"Display\", 4096, NULL, 2, NULL);\n    xTaskCreate(sensorTask, \"Sensors\", 2048, NULL, 1, NULL);\n}\n```"},{"title":"Task Implementation Pattern","content":"```cpp\nvoid displayTask(void *param) {\n    while(1) {\n        // Take display mutex for thread safety\n        if (xSemaphoreTake(displayMutex, portMAX_DELAY)) {\n            updateDisplay();\n            xSemaphoreGive(displayMutex);\n        }\n        vTaskDelay(pdMS_TO_TICKS(50));  // ~20 FPS\n    }\n}\n\nvoid inputTask(void *param) {\n    while(1) {\n        if (touchEvent) {\n            touchEvent = false;\n            handleTouch();\n        }\n        vTaskDelay(pdMS_TO_TICKS(20));  // Check 50x/sec\n    }\n}\n```"},{"title":"Shared Resource Protection","content":"Use mutexes to protect shared resources:\n\n```cpp\nSemaphoreHandle_t displayMutex;\nSemaphoreHandle_t i2cMutex;\n\nvoid setup() {\n    displayMutex = xSemaphoreCreateMutex();\n    i2cMutex = xSemaphoreCreateMutex();\n}\n\n// Before accessing I2C\nxSemaphoreTake(i2cMutex, portMAX_DELAY);\nreadSensor();\nxSemaphoreGive(i2cMutex);\n```"},{"title":"Inter-Task Communication","content":"Use semaphores to signal events:\n```cpp\nSemaphoreHandle_t touchSemaphore;\n\n// In ISR\nvoid IRAM_ATTR touchISR() {\n    xSemaphoreGiveFromISR(touchSemaphore, NULL);\n}\n\n// In input task\nif (xSemaphoreTake(touchSemaphore, portMAX_DELAY)) {\n    handleTouch();\n}\n```"},{"title":"Guidelines","content":"- Assign priorities based on timing sensitivity\n- Use semaphores/notifications for inter-task communication\n- Keep ISRs minimal, defer processing to tasks\n- Ensure tasks do not block each other\n- Monitor stack usage during development"}],"key_points":["High priority for input handling (responsive UI)","Use mutexes to protect shared resources (display, I2C)","Keep ISRs minimal, signal tasks with semaphores","Use vTaskDelay() instead of blocking delays"]}',
3, 60, 1),

('lesson-4-demo', 'mod-4', 'smartwatch-course', 'Module 4 Final Demo', 'Submit a comprehensive video of your complete smartwatch.', 'submission',
'{"instructions":"Record a comprehensive video demonstrating your fully integrated smartwatch. This is your final project demonstration.\n\n**Your video should show:**\n\n1. **Home Screen**\n   - Time and date display\n   - Battery percentage indicator\n\n2. **Step Count Screen**\n   - Current step count displayed\n   - Navigation to/from this screen\n\n3. **Wi-Fi Status Screen**\n   - Connection status display\n   - Reconnect button functionality\n\n4. **Stopwatch Screen**\n   - Start/Stop/Reset functionality\n   - Stopwatch continues when navigating away\n\n5. **Screen Navigation**\n   - Smooth transitions between all screens\n   - Responsive touch interaction\n\n6. **System Responsiveness**\n   - Demonstrate the watch feels responsive\n   - No freezing or lag during transitions\n\n**Video Requirements:**\n- 2-5 minutes\n- Show each feature clearly\n- Brief explanation of your implementation approach\n- Demonstrate the watch working as a cohesive product\n\n**Upload your complete project as a ZIP file.**","submission_type":"video","required_files":["main.cpp","power.h","power.cpp","display.h","display.cpp","mytime.h","mytime.c","mywifi.h","mywifi.cpp","touch.h","touch.c","accel.h","accel.cpp"],"rubric":[{"criteria":"Stopwatch functionality","points":20,"description":"Stopwatch works correctly and persists across screen changes"},{"criteria":"Screen navigation","points":20,"description":"All screens accessible via touch with smooth transitions"},{"criteria":"Battery display","points":15,"description":"Battery percentage shown on home screen with icon"},{"criteria":"RTOS architecture","points":25,"description":"Tasks properly structured with mutexes and semaphores"},{"criteria":"Overall integration","points":20,"description":"Watch behaves as cohesive product, responsive and stable"}]}',
4, 60, 1),

('lesson-4-quiz', 'mod-4', 'smartwatch-course', 'Module 4 Final Quiz', 'Test your understanding of system integration concepts.', 'quiz',
'{"passing_score":70,"time_limit":20,"attempts_allowed":3,"instructions":"This comprehensive quiz tests your understanding of all Module 4 concepts. You need 70% to pass."}',
5, 20, 1);

-- Module 4 Quiz Questions
INSERT INTO quiz_questions (id, lesson_id, question_text, question_type, options_json, correct_answer, explanation, order_index, points)
VALUES 
('q4-1', 'lesson-4-quiz', 'In FreeRTOS, what function should be used instead of delay() for timing?', 'multiple_choice',
'["sleep()","wait()","vTaskDelay()","hold()"]',
'vTaskDelay()',
'vTaskDelay() properly suspends the task and allows other tasks to run, unlike delay() which blocks the entire system.', 0, 10),

('q4-2', 'lesson-4-quiz', 'What should you use to protect shared resources accessed by multiple tasks?', 'multiple_choice',
'["Global variables","Mutex or Semaphore","Static variables","Inline functions"]',
'Mutex or Semaphore',
'Mutexes and semaphores provide synchronization to prevent race conditions when multiple tasks access shared resources like the display or I2C bus.', 1, 10),

('q4-3', 'lesson-4-quiz', 'Which task should typically have the highest priority in a smartwatch UI?', 'multiple_choice',
'["Networking task","Sensor polling task","Input handling task","Data logging task"]',
'Input handling task',
'Input handling should have high priority to ensure the UI feels responsive to user interactions like touch and button presses.', 2, 10),

('q4-4', 'lesson-4-quiz', 'How should the stopwatch maintain its state when switching to another screen?', 'multiple_choice',
'["Stop the stopwatch when leaving the screen","Store state in a global variable separate from display","Reset the stopwatch on every screen change","Pause and resume automatically"]',
'Store state in a global variable separate from display',
'The stopwatch timing logic should be independent of the display. A background variable tracks elapsed time regardless of which screen is shown.', 3, 10),

('q4-5', 'lesson-4-quiz', 'What is the purpose of using an enum for screen states?', 'multiple_choice',
'["Enums use less memory","Enums are faster to process","Enums provide type safety and readability","Enums are required by RTOS"]',
'Enums provide type safety and readability',
'Using an enum like `enum Screen { HOME, STEPS, WIFI, STOPWATCH }` makes code more readable and allows the compiler to catch invalid state values.', 4, 10),

('q4-6', 'lesson-4-quiz', 'How often should battery percentage be updated on the display?', 'multiple_choice',
'["Every frame","Every 100ms","Every 30-60 seconds","Only on user request"]',
'Every 30-60 seconds',
'Battery percentage changes slowly. Updating every 30-60 seconds is sufficient and avoids unnecessary I2C traffic and display updates.', 5, 10);

