INSERT INTO lessons (id, module_id, course_id, title, description, content_type, content_json, order_index, duration_minutes, is_published)
VALUES 
('lesson-5-overview', 'mod-5', 'smartwatch-course', 'Short Circuit Design Challenge', 'Learn about the design challenge prizes and requirements.', 'text',
'{"sections":[{"title":"Challenge Overview","content":"The Short Circuit Design Challenge is our way of recognizing exceptional engineering work. While our project kits establish a strong technical foundation, this challenge is designed for students who extend that foundation through innovation, thoughtful design, and rigorous execution."},{"title":"Cash Prizes","content":"- **First Place:** $1,000\n- **Second Place:** $750\n- **Third Place:** $500"},{"title":"Additional Recognition","content":"**Website Recognition**\nWinning projects will be featured on the Short Circuit website with a project demonstration and contributor profile. This public recognition can be shared with recruiters, academic programs, and professional networks.\n\n**Certificate of Achievement**\nRecipients earn a verified Certificate of Achievement acknowledging design excellence. This credential may be displayed on LinkedIn or included in portfolios and resumes.\n\n**Exclusive Opportunities**\nWinners receive a complimentary future project kit and gain access to a private mentorship and career opportunities group."},{"title":"Eligibility","content":"**You must be an active university student to enter the design challenge.** You will need to provide a university email for consideration."},{"title":"Extension Ideas","content":"**System Architecture & Software Design**\n- Desktop, web, or mobile dashboard for live data\n- Companion app for activity monitoring\n- Firmware update mechanisms\n\n**Power Management & Performance**\n- Adaptive power strategies based on user behavior\n- Advanced sleep/wake mechanisms\n- Power consumption visualization\n\n**Health, Motion & Activity Analysis**\n- Step counting with calorie estimation\n- Activity classification algorithms\n- Motion pattern detection\n\n**User Interface & Experience**\n- Custom watch faces\n- Gesture-based navigation\n- Animated transitions\n\n**Networking, Data & Cloud**\n- Cloud data synchronization\n- Long-term analytics\n- Secure data transfer\n\n**Creative Extensions**\n- Productivity tools (timers, focus modes)\n- Adaptive alarms based on sensors\n- Additional peripheral integration"}],"key_points":["First place wins $1,000","Must be active university student","Meaningfully extend the baseline project","Winners featured on website with exclusive perks"],"callout":{"type":"info","content":"The examples provided are starting points. The strongest projects often explore ideas beyond those listed here."}}',
0, 30, 1),

('lesson-5-baseline', 'mod-5', 'smartwatch-course', 'Baseline Project Upload', 'Upload your completed baseline project for verification.', 'submission',
'{"instructions":"Upload a ZIP file containing your completed baseline smartwatch project.\n\n**Your submission should include:**\n- Your entire project directory\n- All source files (*.h, *.c, *.cpp)\n- platformio.ini configuration\n- A brief README explaining your implementation\n- A final working demo video\n\n**Baseline Requirements:**\nYour baseline project must demonstrate all Module 1-4 functionality:\n- System power and display\n- Timekeeping with RTC and Wi-Fi sync\n- Touch input and accelerometer\n- Screen navigation and stopwatch\n- RTOS-based architecture\n\n**This submission is required before entering the Design Challenge.**","submission_type":"files","required_files":["README.md"],"rubric":[{"criteria":"Completeness","points":40,"description":"All module requirements implemented"},{"criteria":"Functionality","points":40,"description":"All features work correctly as demonstrated"},{"criteria":"Code quality","points":20,"description":"Clean organization, proper abstractions, documented"}]}',
