-- ========================================
-- UPDATE COURSE STATS
-- ========================================
UPDATE courses SET 
  total_lessons = (SELECT COUNT(*) FROM lessons WHERE course_id = 'smartwatch-course' AND is_published = 1),
  total_quizzes = (SELECT COUNT(*) FROM lessons WHERE course_id = 'smartwatch-course' AND content_type = 'quiz' AND is_published = 1)
WHERE id = 'smartwatch-course';
